20	
21	export function handleSlashCommand(
22	  ctx: PluginCommandContext,
23	  _api: OpenClawPluginApi,
24	): PluginCommandResult {
25	  const subcommand = ctx.args?.trim().split(/\s+/)[0] ?? "";
26	
27	  switch (subcommand) {
28	    case "status":
29	      return slashStatus();
30	    case "eject":
31	      return slashEject();
32	    case "onboard":
33	      return slashOnboard();
