21	
22	const SANDBOX_MIGRATION_DIR = "/sandbox/.nemoclaw/migration";
23	const SNAPSHOT_VERSION = 2;
24	
25	export type MigrationRootKind = "workspace" | "agentDir" | "skillsExtraDir";
26	
27	export interface MigrationRootBinding {
28	  configPath: string;
29	}
