31	export interface MigrationExternalRoot {
32	  id: string;
33	  kind: MigrationRootKind;
34	  label: string;
35	  sourcePath: string;
36	  snapshotRelativePath: string;
37	  sandboxPath: string;
38	  symlinkPaths: string[];
