44	  homeDir: string | null;
45	  stateDir: string | null;
46	  configDir: string | null;
47	  configPath: string | null;
48	  workspaceDir: string | null;
49	  extensionsDir: string | null;
50	  skillsDir: string | null;
51	  hooksDir: string | null;
52	  externalRoots: MigrationExternalRoot[];
53	  warnings: string[];
54	  errors: string[];
