78	type CandidateRoot = {
79	  id: string;
80	  kind: MigrationRootKind;
81	  label: string;
82	  sourcePath: string;
83	  sandboxPath: string;
84	  bindings: MigrationRootBinding[];
85	  required: boolean;
86	};
87	
88	type OpenClawConfigDocument = Record<string, unknown>;
89	
90	function resolveHostHome(env: NodeJS.ProcessEnv = process.env): string {
91	  const fallbackHome = env.HOME?.trim() || env.USERPROFILE?.trim() || os.homedir();
92	  const explicitHome = env.OPENCLAW_HOME?.trim();
93	  if (explicitHome) {
94	    if (explicitHome === "~") {
95	      return fallbackHome;
96	    }
97	    if (explicitHome.startsWith("~/") || explicitHome.startsWith("~\\")) {
98	      return path.join(fallbackHome, explicitHome.slice(2));
99	    }
100	    return path.resolve(explicitHome);
101	  }
102	  return fallbackHome;
103	}
104	
105	function resolveUserPath(input: string, env: NodeJS.ProcessEnv = process.env): string {
106	  if (input === "~") {
107	    return resolveHostHome(env);
108	  }
109	  if (input.startsWith("~/") || input.startsWith("~\\")) {
110	    return path.join(resolveHostHome(env), input.slice(2));
111	  }
112	  return path.resolve(input);
113	}
114	
115	function normalizeHostPath(input: string): string {
116	  const resolved = path.resolve(input);
117	  return process.platform === "win32" ? resolved.toLowerCase() : resolved;
118	}
119	
120	function isWithinRoot(candidatePath: string, rootPath: string): boolean {
121	  const candidate = normalizeHostPath(candidatePath);
122	  const root = normalizeHostPath(rootPath);
123	  const relative = path.relative(root, candidate);
124	  return relative === "" || (!relative.startsWith("..") && !path.isAbsolute(relative));
125	}
126	
127	function resolveStateDir(env: NodeJS.ProcessEnv = process.env): string {
128	  const override = env.OPENCLAW_STATE_DIR?.trim();
129	  if (override) {
130	    return resolveUserPath(override, env);
131	  }
132	  return path.join(resolveHostHome(env), ".openclaw");
133	}
134	
135	function resolveConfigPath(stateDir: string, env: NodeJS.ProcessEnv = process.env): string {
136	  const override = env.OPENCLAW_CONFIG_PATH?.trim();
137	  if (override) {
138	    return resolveUserPath(override, env);
139	  }
140	  return path.join(stateDir, "openclaw.json");
141	}
142	
143	function loadConfigDocument(configPath: string): OpenClawConfigDocument | null {
144	  if (!existsSync(configPath)) {
145	    return null;
146	  }
147	  const raw = readFileSync(configPath, "utf-8");
148	  const parsed: unknown = JSON5.parse(raw);
149	  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
150	    throw new Error(`Config at ${configPath} is not a JSON object.`);
151	  }
152	  return parsed as OpenClawConfigDocument;
153	}
154	
155	function collectSymlinkPaths(rootPath: string): string[] {
156	  const symlinks: string[] = [];
157	
158	  function walk(currentPath: string, relativePath: string): void {
159	    const stat = lstatSync(currentPath);
160	    if (stat.isSymbolicLink()) {
161	      symlinks.push(relativePath || ".");
162	      return;
163	    }
164	    if (!stat.isDirectory()) {
165	      return;
166	    }
167	    for (const entry of readdirSync(currentPath)) {
168	      const nextPath = path.join(currentPath, entry);
169	      const nextRelative = relativePath ? path.join(relativePath, entry) : entry;
170	      walk(nextPath, nextRelative);
171	    }
172	  }
173	
174	  walk(rootPath, "");
175	  return symlinks.sort();
176	}
177	
178	function slugify(input: string): string {
179	  const slug = input
180	    .toLowerCase()
181	    .replace(/[^a-z0-9]+/g, "-")
182	    .replace(/^-+|-+$/g, "");
183	  return slug || "root";
184	}
185	
186	function registerRoot(
187	  rootMap: Map<string, CandidateRoot>,
188	  params: {
189	    pathValue: string;
190	    kind: MigrationRootKind;
191	    label: string;
192	    bindingPath: string;
193	    sandboxGroup: string;
194	    required: boolean;
195	  },
196	): void {
197	  const resolvedPath = resolveUserPath(params.pathValue);
198	  const normalized = normalizeHostPath(resolvedPath);
199	  const existing = rootMap.get(normalized);
200	  if (existing) {
201	    existing.bindings.push({ configPath: params.bindingPath });
202	    return;
203	  }
204	
205	  const id = `${params.sandboxGroup}-${slugify(params.label)}`;
206	  rootMap.set(normalized, {
207	    id,
208	    kind: params.kind,
209	    label: params.label,
210	    sourcePath: resolvedPath,
211	    sandboxPath: path.posix.join(SANDBOX_MIGRATION_DIR, params.sandboxGroup, id),
212	    bindings: [{ configPath: params.bindingPath }],
213	    required: params.required,
214	  });
215	}
216	
217	function defaultWorkspacePath(env: NodeJS.ProcessEnv = process.env): string {
218	  const home = resolveHostHome(env);
219	  const profile = env.OPENCLAW_PROFILE?.trim();
220	  if (profile && profile.toLowerCase() !== "default") {
221	    return path.join(home, ".openclaw", `workspace-${profile}`);
222	  }
223	  return path.join(home, ".openclaw", "workspace");
224	}
225	
226	function collectExternalRoots(
227	  config: OpenClawConfigDocument | null,
228	  stateDir: string,
229	): { roots: MigrationExternalRoot[]; warnings: string[]; errors: string[] } {
230	  const warnings: string[] = [];
231	  const errors: string[] = [];
232	  const rootMap = new Map<string, CandidateRoot>();
233	
234	  const agents = config?.["agents"];
235	  const agentDefaults =
236	    agents && typeof agents === "object" && !Array.isArray(agents)
237	      ? (agents as Record<string, unknown>)["defaults"]
238	      : undefined;
239	  const agentList =
240	    agents && typeof agents === "object" && !Array.isArray(agents)
241	      ? (agents as Record<string, unknown>)["list"]
242	      : undefined;
243	  const skills = config?.["skills"];
244	  const skillLoad =
245	    skills && typeof skills === "object" && !Array.isArray(skills)
246	      ? (skills as Record<string, unknown>)["load"]
247	      : undefined;
248	
249	  const defaultsWorkspace =
250	    agentDefaults && typeof agentDefaults === "object" && !Array.isArray(agentDefaults)
251	      ? (agentDefaults as Record<string, unknown>)["workspace"]
252	      : undefined;
253	  const defaultWorkspace =
254	    typeof defaultsWorkspace === "string" && defaultsWorkspace.trim()
255	      ? defaultsWorkspace.trim()
256	      : defaultWorkspacePath();
257	  registerRoot(rootMap, {
258	    pathValue: defaultWorkspace,
259	    kind: "workspace",
260	    label: "default-workspace",
261	    bindingPath: "agents.defaults.workspace",
262	    sandboxGroup: "workspaces",
263	    required: typeof defaultsWorkspace === "string" && defaultsWorkspace.trim().length > 0,
264	  });
265	
266	  if (Array.isArray(agentList)) {
267	    agentList.forEach((entry, index) => {
268	      if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
269	        return;
270	      }
271	      const agent = entry as Record<string, unknown>;
272	      const agentId =
273	        typeof agent["id"] === "string" && agent["id"].trim()
274	          ? agent["id"].trim()
275	          : `agent-${String(index)}`;
276	
277	      if (typeof agent["workspace"] === "string" && agent["workspace"].trim()) {
278	        registerRoot(rootMap, {
279	          pathValue: agent["workspace"].trim(),
280	          kind: "workspace",
281	          label: `${agentId}-workspace`,
282	          bindingPath: `agents.list[${String(index)}].workspace`,
283	          sandboxGroup: "workspaces",
284	          required: true,
285	        });
286	      }
287	
288	      if (typeof agent["agentDir"] === "string" && agent["agentDir"].trim()) {
289	        registerRoot(rootMap, {
290	          pathValue: agent["agentDir"].trim(),
291	          kind: "agentDir",
292	          label: `${agentId}-agent-dir`,
293	          bindingPath: `agents.list[${String(index)}].agentDir`,
294	          sandboxGroup: "agent-dirs",
295	          required: true,
296	        });
297	      }
298	    });
299	  }
300	
301	  const extraDirs =
302	    skillLoad && typeof skillLoad === "object" && !Array.isArray(skillLoad)
303	      ? (skillLoad as Record<string, unknown>)["extraDirs"]
304	      : undefined;
305	  if (Array.isArray(extraDirs)) {
306	    extraDirs.forEach((entry, index) => {
307	      if (typeof entry !== "string" || !entry.trim()) {
308	        return;
309	      }
310	      registerRoot(rootMap, {
311	        pathValue: entry.trim(),
312	        kind: "skillsExtraDir",
313	        label: `skills-extra-${String(index + 1)}`,
314	        bindingPath: `skills.load.extraDirs[${String(index)}]`,
315	        sandboxGroup: "skills",
316	        required: true,
317	      });
318	    });
319	  }
320	
321	  const roots = [...rootMap.values()]
322	    .filter((root) => !isWithinRoot(root.sourcePath, stateDir))
323	    .map<MigrationExternalRoot>((root) => ({
324	      id: root.id,
325	      kind: root.kind,
326	      label: root.label,
327	      sourcePath: root.sourcePath,
328	      snapshotRelativePath: path.join("external", root.id),
329	      sandboxPath: root.sandboxPath,
330	      symlinkPaths: [],
331	      bindings: root.bindings,
332	    }));
333	
334	  const validRoots: MigrationExternalRoot[] = [];
335	  for (const root of roots) {
336	    if (!existsSync(root.sourcePath)) {
337	      const message = `${root.kind} path is missing: ${root.sourcePath} (${root.bindings
338	        .map((binding) => binding.configPath)
339	        .join(", ")})`;
340	      if (rootMap.get(normalizeHostPath(root.sourcePath))?.required) {
341	        errors.push(`Configured ${message}`);
342	      } else {
343	        warnings.push(`Skipping absent optional ${message}`);
344	      }
345	      continue;
346	    }
347	    try {
348	      const stat = lstatSync(root.sourcePath);
349	      if (!stat.isDirectory()) {
350	        errors.push(
351	          `${root.kind} path is not a directory: ${root.sourcePath} (${root.bindings
352	            .map((binding) => binding.configPath)
353	            .join(", ")})`,
354	        );
355	        continue;
356	      }
357	      root.symlinkPaths = collectSymlinkPaths(root.sourcePath);
358	      if (root.symlinkPaths.length > 0) {
359	        warnings.push(
360	          `Preserving ${String(root.symlinkPaths.length)} symlink(s) under ${root.sourcePath} during migration.`,
361	        );
362	      }
363	      validRoots.push(root);
364	    } catch (err: unknown) {
365	      const msg = err instanceof Error ? err.message : String(err);
366	      errors.push(`Failed to inspect ${root.sourcePath}: ${msg}`);
367	    }
368	  }
369	
370	  return { roots: validRoots, warnings, errors };
371	}
372	
373	export function detectHostOpenClaw(env: NodeJS.ProcessEnv = process.env): HostOpenClawState {
374	  const homeDir = resolveHostHome(env);
375	  const stateDir = resolveStateDir(env);
376	  const configPath = resolveConfigPath(stateDir, env);
377	  const stateExists = existsSync(stateDir);
378	  const configExists = existsSync(configPath);
379	
380	  if (!stateExists && !configExists) {
381	    return {
382	      exists: false,
383	      homeDir,
384	      stateDir: null,
385	      configDir: null,
386	      configPath: null,
387	      workspaceDir: null,
388	      extensionsDir: null,
389	      skillsDir: null,
390	      hooksDir: null,
391	      externalRoots: [],
392	      warnings: [],
393	      errors: [],
394	      hasExternalConfig: false,
395	    };
396	  }
397	
398	  const errors: string[] = [];
399	  const warnings: string[] = [];
400	  let config: OpenClawConfigDocument | null = null;
401	
402	  if (!stateExists) {
403	    errors.push(`Resolved OpenClaw state directory does not exist: ${stateDir}`);
404	  }
405	
406	  try {
407	    config = loadConfigDocument(configPath);
408	  } catch (err: unknown) {
409	    const msg = err instanceof Error ? err.message : String(err);
410	    errors.push(`Failed to parse OpenClaw config at ${configPath}: ${msg}`);
411	  }
412	
413	  const rootInfo = collectExternalRoots(config, stateDir);
414	  warnings.push(...rootInfo.warnings);
415	  errors.push(...rootInfo.errors);
416	
417	  const workspaceDir =
418	    config &&
419	    typeof config["agents"] === "object" &&
420	    config["agents"] &&
421	    !Array.isArray(config["agents"]) &&
422	    typeof (
423	      (config["agents"] as Record<string, unknown>)["defaults"] as
424	        | Record<string, unknown>
425	        | undefined
426	    )?.["workspace"] === "string"
427	      ? resolveUserPath(
428	          (
429	            ((config["agents"] as Record<string, unknown>)["defaults"] as Record<string, unknown>)[
430	              "workspace"
431	            ] as string
432	          ).trim(),
433	          env,
434	        )
435	      : defaultWorkspacePath(env);
436	
437	  const extensionsDir = existsSync(path.join(stateDir, "extensions"))
438	    ? path.join(stateDir, "extensions")
439	    : null;
440	  const skillsDir = existsSync(path.join(stateDir, "skills"))
441	    ? path.join(stateDir, "skills")
442	    : null;
443	  const hooksDir = existsSync(path.join(stateDir, "hooks")) ? path.join(stateDir, "hooks") : null;
444	
445	  if (existsSync(workspaceDir)) {
446	    try {
447	      const symlinkPaths = collectSymlinkPaths(workspaceDir);
448	      if (symlinkPaths.length > 0) {
449	        warnings.push(
450	          `Primary workspace contains ${String(symlinkPaths.length)} symlink(s): ${workspaceDir}.`,
451	        );
452	      }
453	    } catch (err: unknown) {
454	      const msg = err instanceof Error ? err.message : String(err);
455	      warnings.push(`Failed to inspect workspace symlinks at ${workspaceDir}: ${msg}`);
456	    }
457	  }
458	
459	  return {
460	    exists: true,
461	    homeDir,
462	    stateDir,
463	    configDir: stateDir,
464	    configPath: configExists ? configPath : null,
465	    workspaceDir: existsSync(workspaceDir) ? workspaceDir : null,
466	    extensionsDir,
467	    skillsDir,
468	    hooksDir,
469	    externalRoots: rootInfo.roots,
470	    warnings,
471	    errors,
472	    hasExternalConfig: configExists && !isWithinRoot(configPath, stateDir),
473	  };
474	}
475	
476	function copyDirectory(sourcePath: string, destinationPath: string): void {
477	  cpSync(sourcePath, destinationPath, {
478	    recursive: true,
479	  });
480	}
481	
482	function writeSnapshotManifest(snapshotDir: string, manifest: SnapshotManifest): void {
483	  writeFileSync(path.join(snapshotDir, "snapshot.json"), JSON.stringify(manifest, null, 2));
484	}
485	
486	function readSnapshotManifest(snapshotDir: string): SnapshotManifest {
487	  return JSON.parse(
488	    readFileSync(path.join(snapshotDir, "snapshot.json"), "utf-8"),
489	  ) as SnapshotManifest;
490	}
491	
492	function resolveConfigSourcePath(manifest: SnapshotManifest, snapshotDir: string): string {
493	  if (manifest.hasExternalConfig) {
494	    return path.join(snapshotDir, "config", "openclaw.json");
495	  }
496	  return path.join(snapshotDir, "openclaw", "openclaw.json");
497	}
498	
499	function setConfigValue(
500	  document: Record<string, unknown>,
501	  configPath: string,
502	  value: string,
503	): void {
504	  const tokens = configPath.match(/[^.[\]]+/g);
505	  if (!tokens || tokens.length === 0) {
506	    throw new Error(`Invalid config path: ${configPath}`);
507	  }
508	
509	  let current: unknown = document;
510	  for (let index = 0; index < tokens.length - 1; index += 1) {
511	    const token = tokens[index];
512	    const nextToken = tokens[index + 1];
513	    if (!token || !nextToken) {
514	      throw new Error(`Invalid config path segment in ${configPath}`);
515	    }
516	    const isArrayIndex = /^\d+$/.test(token);
517	
518	    if (isArrayIndex) {
519	      const array = current as unknown[];
520	      const entry = array[Number.parseInt(token, 10)];
521	      if (entry == null) {
522	        array[Number.parseInt(token, 10)] = /^\d+$/.test(nextToken) ? [] : {};
523	      }
524	      current = array[Number.parseInt(token, 10)];
525	      continue;
526	    }
527	
528	    const record = current as Record<string, unknown>;
529	    if (!record[token] || typeof record[token] !== "object") {
530	      record[token] = /^\d+$/.test(nextToken) ? [] : {};
531	    }
532	    current = record[token];
533	  }
534	
535	  const finalToken = tokens[tokens.length - 1];
536	  if (!finalToken) {
537	    throw new Error(`Missing final config path segment in ${configPath}`);
538	  }
539	  if (/^\d+$/.test(finalToken)) {
540	    const array = current as unknown[];
541	    array[Number.parseInt(finalToken, 10)] = value;
542	    return;
543	  }
544	  (current as Record<string, unknown>)[finalToken] = value;
545	}
546	
547	function prepareSandboxState(snapshotDir: string, manifest: SnapshotManifest): string {
548	  const preparedStateDir = path.join(snapshotDir, "sandbox-bundle", "openclaw");
549	  rmSync(preparedStateDir, { recursive: true, force: true });
550	  mkdirSync(path.dirname(preparedStateDir), { recursive: true });
551	  copyDirectory(path.join(snapshotDir, "openclaw"), preparedStateDir);
552	
553	  const configSourcePath = resolveConfigSourcePath(manifest, snapshotDir);
554	  const config = existsSync(configSourcePath) ? (loadConfigDocument(configSourcePath) ?? {}) : {};
555	
556	  for (const root of manifest.externalRoots) {
557	    for (const binding of root.bindings) {
558	      setConfigValue(config, binding.configPath, root.sandboxPath);
559	    }
560	  }
561	
562	  writeFileSync(path.join(preparedStateDir, "openclaw.json"), JSON.stringify(config, null, 2));
563	  return preparedStateDir;
564	}
565	
566	export function createSnapshotBundle(
567	  hostState: HostOpenClawState,
568	  logger: PluginLogger,
569	  options: { persist: boolean },
570	): SnapshotBundle | null {
571	  if (!hostState.stateDir || !hostState.homeDir) {
572	    logger.error("Cannot snapshot host OpenClaw state: no state directory was resolved.");
573	    return null;
574	  }
575	
576	  const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
577	  const parentDir = path.join(
578	    hostState.homeDir,
579	    ".nemoclaw",
580	    options.persist ? "snapshots" : "staging",
581	    timestamp,
582	  );
583	
584	  try {
585	    mkdirSync(parentDir, { recursive: true });
586	    const snapshotStateDir = path.join(parentDir, "openclaw");
587	    copyDirectory(hostState.stateDir, snapshotStateDir);
588	
589	    if (hostState.configPath && hostState.hasExternalConfig) {
590	      const configSnapshotDir = path.join(parentDir, "config");
591	      mkdirSync(configSnapshotDir, { recursive: true });
592	      copyFileSync(hostState.configPath, path.join(configSnapshotDir, "openclaw.json"));
593	    }
594	
595	    const externalRoots: MigrationExternalRoot[] = [];
596	    for (const root of hostState.externalRoots) {
597	      const destination = path.join(parentDir, root.snapshotRelativePath);
598	      mkdirSync(path.dirname(destination), { recursive: true });
599	      copyDirectory(root.sourcePath, destination);
600	      externalRoots.push({
601	        ...root,
602	        symlinkPaths: collectSymlinkPaths(root.sourcePath),
603	      });
604	    }
605	
606	    const manifest: SnapshotManifest = {
607	      version: SNAPSHOT_VERSION,
608	      createdAt: new Date().toISOString(),
609	      homeDir: hostState.homeDir,
610	      stateDir: hostState.stateDir,
611	      configPath: hostState.configPath,
612	      hasExternalConfig: hostState.hasExternalConfig,
613	      externalRoots,
614	      warnings: hostState.warnings,
615	    };
616	
617	    writeSnapshotManifest(parentDir, manifest);
618	
619	    return {
620	      snapshotDir: parentDir,
621	      snapshotPath: path.join(parentDir, "snapshot.json"),
622	      preparedStateDir: prepareSandboxState(parentDir, manifest),
623	      archivesDir: path.join(parentDir, "sandbox-bundle", "archives"),
624	      manifest,
625	      temporary: !options.persist,
626	    };
627	  } catch (err: unknown) {
628	    const msg = err instanceof Error ? err.message : String(err);
629	    logger.error(`Snapshot failed: ${msg}`);
630	    return null;
631	  }
632	}
633	
634	export function cleanupSnapshotBundle(bundle: SnapshotBundle): void {
635	  if (bundle.temporary) {
636	    rmSync(bundle.snapshotDir, { recursive: true, force: true });
637	  }
638	}
639	
640	export async function createArchiveFromDirectory(
641	  sourceDir: string,
642	  archivePath: string,
643	): Promise<void> {
644	  mkdirSync(path.dirname(archivePath), { recursive: true });
645	  await createTar(
646	    {
647	      cwd: sourceDir,
648	      file: archivePath,
649	      portable: true,
650	      follow: false,
651	      noMtime: true,
652	    },
653	    ["."],
654	  );
655	}
656	
657	export function loadSnapshotManifest(snapshotDir: string): SnapshotManifest {
658	  return readSnapshotManifest(snapshotDir);
659	}
660	
661	export function restoreSnapshotToHost(snapshotDir: string, logger: PluginLogger): boolean {
662	  const manifest = readSnapshotManifest(snapshotDir);
663	  const snapshotStateDir = path.join(snapshotDir, "openclaw");
664	  if (!existsSync(snapshotStateDir)) {
665	    logger.error(`Snapshot directory not found: ${snapshotStateDir}`);
666	    return false;
667	  }
668	
669	  // SECURITY (C-4): Validate that write targets are within a trusted root.
670	  // Use the host's actual home directory — NOT manifest.homeDir which is
671	  // attacker-controlled data from the snapshot JSON.
672	  const trustedRoot = resolveHostHome();
673	
674	  // Validate manifest.homeDir itself is within trusted root
675	  if (typeof manifest.homeDir !== "string" || !isWithinRoot(manifest.homeDir, trustedRoot)) {
676	    logger.error(
677	      `Snapshot manifest homeDir is outside the trusted host root. ` +
678	        `Refusing to restore. homeDir=${manifest.homeDir}, trustedRoot=${trustedRoot}`,
679	    );
680	    return false;
681	  }
682	
683	  // Validate stateDir type and containment
684	  if (typeof manifest.stateDir !== "string") {
685	    logger.error(`Snapshot manifest stateDir is not a string. Refusing to restore.`);
686	    return false;
687	  }
688	
689	  // Support OPENCLAW_STATE_DIR env override: when set, require exact match
690	  const envStateDir = process.env.OPENCLAW_STATE_DIR?.trim();
691	  if (envStateDir) {
692	    const resolvedEnvStateDir = resolveUserPath(envStateDir);
693	    if (normalizeHostPath(manifest.stateDir) !== normalizeHostPath(resolvedEnvStateDir)) {
694	      logger.error(
695	        `Snapshot manifest stateDir does not match OPENCLAW_STATE_DIR. ` +
696	          `Refusing to restore. stateDir=${manifest.stateDir}, expected=${resolvedEnvStateDir}`,
697	      );
698	      return false;
699	    }
700	  } else if (!isWithinRoot(manifest.stateDir, trustedRoot)) {
701	    logger.error(
702	      `Snapshot manifest stateDir is outside the trusted host root. ` +
703	        `Refusing to restore. stateDir=${manifest.stateDir}, trustedRoot=${trustedRoot}`,
704	    );
705	    return false;
706	  }
707	
708	  if (manifest.hasExternalConfig) {
709	    // Validate configPath type — fail closed when hasExternalConfig is true
710	    // but configPath is null/empty (partial restore would silently skip config).
711	    if (typeof manifest.configPath !== "string" || !manifest.configPath.trim()) {
712	      logger.error(
713	        `Snapshot manifest has hasExternalConfig=true but configPath is missing or empty. Refusing to restore.`,
714	      );
715	      return false;
716	    }
717	
718	    // Support OPENCLAW_CONFIG_PATH env override: when set, require exact match
719	    const envConfigPath = process.env.OPENCLAW_CONFIG_PATH?.trim();
720	    if (envConfigPath) {
721	      const resolvedEnvConfigPath = resolveUserPath(envConfigPath);
722	      if (normalizeHostPath(manifest.configPath) !== normalizeHostPath(resolvedEnvConfigPath)) {
723	        logger.error(
724	          `Snapshot manifest configPath does not match OPENCLAW_CONFIG_PATH. ` +
725	            `Refusing to restore. configPath=${manifest.configPath}, expected=${resolvedEnvConfigPath}`,
726	        );
727	        return false;
728	      }
729	    } else if (!isWithinRoot(manifest.configPath, trustedRoot)) {
730	      logger.error(
731	        `Snapshot manifest configPath is outside the trusted host root. ` +
732	          `Refusing to restore. configPath=${manifest.configPath}, trustedRoot=${trustedRoot}`,
733	      );
734	      return false;
735	    }
736	  }
737	
738	  try {
739	    if (existsSync(manifest.stateDir)) {
740	      const archiveName = `${manifest.stateDir}.nemoclaw-archived-${String(Date.now())}`;
741	      renameSync(manifest.stateDir, archiveName);
742	      logger.info(`Archived current state directory to ${archiveName}`);
743	    }
744	
745	    mkdirSync(path.dirname(manifest.stateDir), { recursive: true });
746	    copyDirectory(snapshotStateDir, manifest.stateDir);
747	
748	    if (manifest.hasExternalConfig && manifest.configPath) {
749	      const configSnapshotPath = path.join(snapshotDir, "config", "openclaw.json");
750	      mkdirSync(path.dirname(manifest.configPath), { recursive: true });
751	      copyFileSync(configSnapshotPath, manifest.configPath);
752	      logger.info(`Restored external config to ${manifest.configPath}`);
753	    }
754	
755	    logger.info("Host OpenClaw state restored.");
756	    return true;
757	  } catch (err: unknown) {
758	    const msg = err instanceof Error ? err.message : String(err);
759	    logger.error(`Restoration failed: ${msg}`);
760	    return false;
761	  }
762	}
