474	async function createSandbox(gpu) {
475	  step(3, 7, "Creating sandbox");
476	
477	  const nameAnswer = await promptOrDefault(
478	    "  Sandbox name (lowercase, numbers, hyphens) [my-assistant]: ",
479	    "NEMOCLAW_SANDBOX_NAME", "my-assistant"
480	  );
481	  const sandboxName = (nameAnswer || "my-assistant").trim().toLowerCase();
482	
483	  // Validate: RFC 1123 subdomain — lowercase alphanumeric and hyphens,
484	  // must start and end with alphanumeric (required by Kubernetes/OpenShell)
485	  if (!/^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/.test(sandboxName)) {
486	    console.error(`  Invalid sandbox name: '${sandboxName}'`);
487	    console.error("  Names must be lowercase, contain only letters, numbers, and hyphens,");
488	    console.error("  and must start and end with a letter or number.");
489	    process.exit(1);
490	  }
491	
492	  // Check if sandbox already exists in registry
493	  const existing = registry.getSandbox(sandboxName);
494	  if (existing) {
495	    if (isNonInteractive()) {
496	      if (process.env.NEMOCLAW_RECREATE_SANDBOX !== "1") {
497	        console.error(`  Sandbox '${sandboxName}' already exists.`);
498	        console.error("  Set NEMOCLAW_RECREATE_SANDBOX=1 to recreate it in non-interactive mode.");
499	        process.exit(1);
500	      }
501	      note(`  [non-interactive] Sandbox '${sandboxName}' exists — recreating`);
502	    } else {
503	      const recreate = await prompt(`  Sandbox '${sandboxName}' already exists. Recreate? [y/N]: `);
504	      if (recreate.toLowerCase() !== "y") {
505	        console.log("  Keeping existing sandbox.");
506	        return sandboxName;
507	      }
508	    }
509	    // Destroy old sandbox
510	    run(`openshell sandbox delete "${sandboxName}" 2>/dev/null || true`, { ignoreError: true });
511	    registry.removeSandbox(sandboxName);
512	  }
513	
514	  // Stage build context
515	  const { mkdtempSync } = require("fs");
516	  const os = require("os");
517	  const buildCtx = fs.mkdtempSync(path.join(os.tmpdir(), "nemoclaw-build-"));
518	  fs.copyFileSync(path.join(ROOT, "Dockerfile"), path.join(buildCtx, "Dockerfile"));
519	  run(`cp -r "${path.join(ROOT, "nemoclaw")}" "${buildCtx}/nemoclaw"`);
520	  run(`cp -r "${path.join(ROOT, "nemoclaw-blueprint")}" "${buildCtx}/nemoclaw-blueprint"`);
521	  run(`cp -r "${path.join(ROOT, "scripts")}" "${buildCtx}/scripts"`);
522	  run(`rm -rf "${buildCtx}/nemoclaw/node_modules"`, { ignoreError: true });
523	
524	  // Create sandbox (use -- echo to avoid dropping into interactive shell)
525	  // Pass the base policy so sandbox starts in proxy mode (required for policy updates later)
526	  const basePolicyPath = path.join(ROOT, "nemoclaw-blueprint", "policies", "openclaw-sandbox.yaml");
527	  const createArgs = [
528	    `--from "${buildCtx}/Dockerfile"`,
529	    `--name "${sandboxName}"`,
530	    `--policy "${basePolicyPath}"`,
531	  ];
532	  // --gpu is intentionally omitted. See comment in startGateway().
533	
534	  console.log(`  Creating sandbox '${sandboxName}' (this takes a few minutes on first run)...`);
535	  const chatUiUrl = process.env.CHAT_UI_URL || 'http://127.0.0.1:18789';
536	  const envArgs = [`CHAT_UI_URL=${shellQuote(chatUiUrl)}`];
537	  if (process.env.NVIDIA_API_KEY) {
538	    envArgs.push(`NVIDIA_API_KEY=${shellQuote(process.env.NVIDIA_API_KEY)}`);
539	  }
540	  const discordToken = getCredential("DISCORD_BOT_TOKEN") || process.env.DISCORD_BOT_TOKEN;
541	  if (discordToken) {
542	    envArgs.push(`DISCORD_BOT_TOKEN=${shellQuote(discordToken)}`);
543	  }
544	  const slackToken = getCredential("SLACK_BOT_TOKEN") || process.env.SLACK_BOT_TOKEN;
545	  if (slackToken) {
546	    envArgs.push(`SLACK_BOT_TOKEN=${shellQuote(slackToken)}`);
547	  }
548	
549	  // Run without piping through awk — the pipe masked non-zero exit codes
550	  // from openshell because bash returns the status of the last pipeline
551	  // command (awk, always 0) unless pipefail is set. Removing the pipe
552	  // lets the real exit code flow through to run().
553	  const createResult = await streamSandboxCreate(
554	    `openshell sandbox create ${createArgs.join(" ")} -- env ${envArgs.join(" ")} nemoclaw-start 2>&1`
555	  );
556	
557	  // Clean up build context regardless of outcome
558	  run(`rm -rf "${buildCtx}"`, { ignoreError: true });
559	
560	  if (createResult.status !== 0) {
561	    console.error("");
562	    console.error(`  Sandbox creation failed (exit ${createResult.status}).`);
563	    if (createResult.output) {
564	      console.error("");
565	      console.error(createResult.output);
566	    }
567	    console.error("  Try:  openshell sandbox list        # check gateway state");
568	    console.error("  Try:  nemoclaw onboard              # retry from scratch");
569	    process.exit(createResult.status || 1);
570	  }
571	
572	  // Wait for sandbox to reach Ready state in k3s before registering.
573	  // On WSL2 + Docker Desktop the pod can take longer to initialize;
574	  // without this gate, NemoClaw registers a phantom sandbox that
575	  // causes "sandbox not found" on every subsequent connect/status call.
576	  console.log("  Waiting for sandbox to become ready...");
577	  let ready = false;
578	  for (let i = 0; i < 30; i++) {
579	    const list = runCapture("openshell sandbox list 2>&1", { ignoreError: true });
580	    if (isSandboxReady(list, sandboxName)) {
581	      ready = true;
582	      break;
583	    }
584	    require("child_process").spawnSync("sleep", ["2"]);
585	  }
586	
587	  if (!ready) {
588	    // Clean up the orphaned sandbox so the next onboard retry with the same
589	    // name doesn't fail on "sandbox already exists".
590	    const delResult = run(`openshell sandbox delete "${sandboxName}" 2>/dev/null || true`, { ignoreError: true });
591	    console.error("");
592	    console.error(`  Sandbox '${sandboxName}' was created but did not become ready within 60s.`);
593	    if (delResult.status === 0) {
594	      console.error("  The orphaned sandbox has been removed — you can safely retry.");
595	    } else {
596	      console.error(`  Could not remove the orphaned sandbox. Manual cleanup:`);
597	      console.error(`    openshell sandbox delete "${sandboxName}"`);
598	    }
599	    console.error("  Retry: nemoclaw onboard");
600	    process.exit(1);
601	  }
602	
603	  // Release any stale forward on port 18789 before claiming it for the new sandbox.
604	  // A previous onboard run may have left the port forwarded to a different sandbox,
605	  // which would silently prevent the new sandbox's dashboard from being reachable.
606	  run(`openshell forward stop 18789 2>/dev/null || true`, { ignoreError: true });
607	  // Forward dashboard port to the new sandbox
608	  run(`openshell forward start --background 18789 "${sandboxName}"`, { ignoreError: true });
609	
610	  // Register only after confirmed ready — prevents phantom entries
611	  registry.registerSandbox({
612	    name: sandboxName,
613	    gpuEnabled: !!gpu,
614	  });
615	
616	  console.log(`  ✓ Sandbox '${sandboxName}' created`);
617	  return sandboxName;
618	}
