871	// ── Step 6: OpenClaw ─────────────────────────────────────────────
872	
873	async function setupOpenclaw(sandboxName, model, provider) {
874	  step(6, 7, "Setting up OpenClaw inside sandbox");
875	
876	  const selectionConfig = getProviderSelectionConfig(provider, model);
877	  if (selectionConfig) {
