893	  console.log("  ✓ OpenClaw gateway launched inside sandbox");
894	}
895	
896	// ── Step 7: Policy presets ───────────────────────────────────────
897	
898	async function setupPolicies(sandboxName) {
899	  step(7, 7, "Policy presets");
900	
901	  const suggestions = ["pypi", "npm"];
902	
903	  // Auto-detect based on env tokens
904	  if (getCredential("TELEGRAM_BOT_TOKEN")) {
