915	  }
916	
917	  const allPresets = policies.listPresets();
918	  const applied = policies.getAppliedPresets(sandboxName);
919	
920	  if (isNonInteractive()) {
921	    const policyMode = (process.env.NEMOCLAW_POLICY_MODE || "suggested").trim().toLowerCase();
922	    let selectedPresets = suggestions;
923	
924	    if (policyMode === "skip" || policyMode === "none" || policyMode === "no") {
925	      note("  [non-interactive] Skipping policy presets.");
926	      return;
927	    }
928	
929	    if (policyMode === "custom" || policyMode === "list") {
930	      selectedPresets = parsePolicyPresetEnv(process.env.NEMOCLAW_POLICY_PRESETS);
931	      if (selectedPresets.length === 0) {
932	        console.error("  NEMOCLAW_POLICY_PRESETS is required when NEMOCLAW_POLICY_MODE=custom.");
933	        process.exit(1);
934	      }
935	    } else if (policyMode === "suggested" || policyMode === "default" || policyMode === "auto") {
936	      const envPresets = parsePolicyPresetEnv(process.env.NEMOCLAW_POLICY_PRESETS);
937	      if (envPresets.length > 0) {
938	        selectedPresets = envPresets;
939	      }
940	    } else {
941	      console.error(`  Unsupported NEMOCLAW_POLICY_MODE: ${policyMode}`);
942	      console.error("  Valid values: suggested, custom, skip");
943	      process.exit(1);
944	    }
945	
946	    const knownPresets = new Set(allPresets.map((p) => p.name));
947	    const invalidPresets = selectedPresets.filter((name) => !knownPresets.has(name));
948	    if (invalidPresets.length > 0) {
949	      console.error(`  Unknown policy preset(s): ${invalidPresets.join(", ")}`);
950	      process.exit(1);
