957	    note(`  [non-interactive] Applying policy presets: ${selectedPresets.join(", ")}`);
958	    for (const name of selectedPresets) {
959	      for (let attempt = 0; attempt < 3; attempt += 1) {
960	        try {
961	          policies.applyPreset(sandboxName, name);
962	          break;
963	        } catch (err) {
964	          const message = err && err.message ? err.message : String(err);
965	          if (!message.includes("sandbox not found") || attempt === 2) {
966	            throw err;
967	          }
968	          sleep(2);
969	        }
970	      }
971	    }
972	  } else {
973	    console.log("");
974	    console.log("  Available policy presets:");
975	    allPresets.forEach((p) => {
976	      const marker = applied.includes(p.name) ? "●" : "○";
977	      const suggested = suggestions.includes(p.name) ? " (suggested)" : "";
978	      console.log(`    ${marker} ${p.name} — ${p.description}${suggested}`);
979	    });
980	    console.log("");
981	
982	    const answer = await prompt(`  Apply suggested presets (${suggestions.join(", ")})? [Y/n/list]: `);
983	
984	    if (answer.toLowerCase() === "n") {
985	      console.log("  Skipping policy presets.");
986	      return;
987	    }
988	
989	    if (answer.toLowerCase() === "list") {
990	      // Let user pick
991	      const picks = await prompt("  Enter preset names (comma-separated): ");
992	      const selected = picks.split(",").map((s) => s.trim()).filter(Boolean);
993	      for (const name of selected) {
994	        policies.applyPreset(sandboxName, name);
995	      }
996	    } else {
997	      // Apply suggested
998	      for (const name of suggestions) {
999	        policies.applyPreset(sandboxName, name);
1000	      }
1001	    }
1002	  }
1003	
1004	  console.log("  ✓ Policies applied");
1005	}
1006	
1007	// ── Dashboard ────────────────────────────────────────────────────
1008	
1009	function printDashboard(sandboxName, model, provider) {
1010	  const nimStat = nim.nimStatus(sandboxName);
1011	  const nimLabel = nimStat.running ? "running" : "not running";
1012	
1013	  let providerLabel = provider;
1014	  if (provider === "nvidia-nim") providerLabel = "NVIDIA Endpoint API";
1015	  else if (provider === "vllm-local") providerLabel = "Local vLLM";
1016	  else if (provider === "ollama-local") providerLabel = "Local Ollama";
1017	
1018	  console.log("");
1019	  console.log(`  ${"─".repeat(50)}`);
1020	  // console.log(`  Dashboard    http://localhost:18789/`);
1021	  console.log(`  Sandbox      ${sandboxName} (Landlock + seccomp + netns)`);
1022	  console.log(`  Model        ${model} (${providerLabel})`);
1023	  console.log(`  NIM          ${nimLabel}`);
1024	  console.log(`  ${"─".repeat(50)}`);
1025	  console.log(`  Next:`);
