1030	  console.log("");
1031	}
1032	
1033	// ── Main ─────────────────────────────────────────────────────────
1034	
1035	async function onboard(opts = {}) {
1036	  NON_INTERACTIVE = opts.nonInteractive || process.env.NEMOCLAW_NON_INTERACTIVE === "1";
1037	
1038	  console.log("");
